from flask import Flask, request, jsonify
from web3 import Web3
from eth_account.messages import encode_defunct
from eth_utils import is_checksum_address, to_checksum_address
import os
import time
import secrets
from typing import Dict, Any

app = Flask(__name__)

w3 = Web3()

NONCE_TTL_SECONDS = int(os.getenv("NONCE_TTL_SECONDS", "300"))
SESSION_TTL_SECONDS = int(os.getenv("SESSION_TTL_SECONDS", "86400"))

nonces: Dict[str, Dict[str, Any]] = {}
sessions: Dict[str, Dict[str, Any]] = {}


def now_ts() -> int:
    return int(time.time())


def cleanup_expired() -> None:
    current = now_ts()

    expired_nonces = [
        address for address, data in nonces.items()
        if data["expires_at"] <= current
    ]
    for address in expired_nonces:
        del nonces[address]

    expired_sessions = [
        token for token, data in sessions.items()
        if data["expires_at"] <= current
    ]
    for token in expired_sessions:
        del sessions[token]


def normalize_address(address: str) -> str:
    if not isinstance(address, str):
        raise ValueError("Address must be a string")
    if not Web3.is_address(address):
        raise ValueError("Invalid Ethereum address")
    return to_checksum_address(address)


def build_auth_message(address: str, nonce: str) -> str:
    return f"Sign this message to authenticate.\nAddress: {address}\nNonce: {nonce}"


def issue_nonce(address: str) -> Dict[str, Any]:
    cleanup_expired()
    checksum_address = normalize_address(address)
    nonce = secrets.token_urlsafe(24)
    expires_at = now_ts() + NONCE_TTL_SECONDS
    message = build_auth_message(checksum_address, nonce)

    nonces[checksum_address] = {
        "nonce": nonce,
        "message": message,
        "expires_at": expires_at,
    }

    return {
        "address": checksum_address,
        "nonce": nonce,
        "message": message,
        "expires_at": expires_at,
    }


def verify_signature(address: str, signature: str, message: str) -> bool:
    checksum_address = normalize_address(address)
    encoded_message = encode_defunct(text=message)
    recovered = w3.eth.account.recover_message(encoded_message, signature=signature)
    recovered_checksum = to_checksum_address(recovered)
    return recovered_checksum == checksum_address


def create_session(address: str) -> Dict[str, Any]:
    token = secrets.token_urlsafe(32)
    expires_at = now_ts() + SESSION_TTL_SECONDS
    sessions[token] = {
        "address": address,
        "created_at": now_ts(),
        "expires_at": expires_at,
    }
    return {
        "token": token,
        "address": address,
        "expires_at": expires_at,
    }


def require_json(required_fields):
    data = request.get_json(silent=True)
    if not data:
        return None, jsonify({"error": "Invalid or missing JSON body"}), 400

    missing = [field for field in required_fields if field not in data]
    if missing:
        return None, jsonify({"error": f"Missing required fields: {', '.join(missing)}"}), 400

    return data, None, None


@app.route("/health", methods=["GET"])
def health():
    cleanup_expired()
    return jsonify({"status": "ok"}), 200


@app.route("/auth/nonce", methods=["POST"])
def auth_nonce():
    data, error_response, status = require_json(["address"])
    if error_response:
        return error_response, status

    try:
        result = issue_nonce(data["address"])
        return jsonify(result), 200
    except ValueError as e:
        return jsonify({"error": str(e)}), 400


@app.route("/auth/verify", methods=["POST"])
def auth_verify():
    data, error_response, status = require_json(["address", "signature"])
    if error_response:
        return error_response, status

    cleanup_expired()

    try:
        address = normalize_address(data["address"])
    except ValueError as e:
        return jsonify({"error": str(e)}), 400

    signature = data["signature"]

    nonce_record = nonces.get(address)
    if not nonce_record:
        return jsonify({"error": "No active nonce for address"}), 400

    if nonce_record["expires_at"] <= now_ts():
        del nonces[address]
        return jsonify({"error": "Nonce expired"}), 400

    message = nonce_record["message"]

    try:
        valid = verify_signature(address, signature, message)
    except Exception:
        return jsonify({"error": "Invalid signature format or verification failed"}), 400

    if not valid:
        return jsonify({"authenticated": False, "error": "Signature does not match address"}), 401

    del nonces[address]
    session = create_session(address)

    return jsonify({
        "authenticated": True,
        "address": address,
        "session": session,
    }), 200


@app.route("/auth/session", methods=["GET"])
def auth_session():
    cleanup_expired()
    auth_header = request.headers.get("Authorization", "")
    if not auth_header.startswith("Bearer "):
        return jsonify({"authenticated": False, "error": "Missing bearer token"}), 401

    token = auth_header.split(" ", 1)[1].strip()
    session = sessions.get(token)
    if not session:
        return jsonify({"authenticated": False, "error": "Invalid or expired session"}), 401

    return jsonify({
        "authenticated": True,
        "address": session["address"],
        "expires_at": session["expires_at"],
    }), 200


@app.route("/auth/logout", methods=["POST"])
def auth_logout():
    cleanup_expired()
    auth_header = request.headers.get("Authorization", "")
    if not auth_header.startswith("Bearer "):
        return jsonify({"success": True}), 200

    token = auth_header.split(" ", 1)[1].strip()
    sessions.pop(token, None)
    return jsonify({"success": True}), 200


